// TypeScript implementation for TS Compilation Flow
interface TSCompilationFlowPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processTSCompilationFlow(item: TSCompilationFlowPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processTSCompilationFlow({ id: 1, title: 'TS Compilation Flow', status: 'active' }));
